echo "=== SGen worker - detailed lookup ==="
for addr in 0x2f4b20 0x2f4c84; do
  echo "--- pc $addr ---"
  addr2line -e /tmp/symbols/_.debug -f -C -i -a "$addr" 2>&1
  echo ""
done

# Also try with function-only (nm) to find enclosing function
echo "=== Nearest symbols ==="
for addr in 0x2f4b20 0x2f4c84; do
  echo -n "  pc $addr: "
  # Find the nearest preceding symbol
  nm -C /tmp/symbols/_.debug 2>/dev/null | awk -v target="$addr" '
    BEGIN { target_dec = strtonum(target) }
    /^[0-9a-f]+ [TtWw]/ {
      sym_addr = strtonum("0x" $1)
      if (sym_addr <= target_dec) {
        best_name = $3; best_addr = $1; offset = target_dec - sym_addr
      }
    }
    END { if (best_name) printf "%s+0x%x (at 0x%s)\n", best_name, offset, best_addr }
  '
done", "description": "Resolve SGen worker symbols", "initial_wait": 15}

