arguments.command:
DBGFILE="/tmp/sv-58cf9d48a5f04192b1871343fde17e20/symbols/_.debug"

# Use readelf to find the DWARF subprogram (function) containing these addresses
# Search for DW_TAG_subprogram entries that encompass our target addresses
python3 -c "
import subprocess, re

result = subprocess.run(['readelf', '--debug-dump=info', '$DBGFILE'], 
                       capture_output=True, text=True, timeout=60)

lines = result.stdout.split('\n')
targets = [0x2f4b20, 0x2f4c84]
current_func = None
low_pc = None

for line in lines:
    if 'DW_TAG_subprogram' in line:
        current_func = {'name': '?', 'low_pc': 0, 'high_pc': 0, 'file': '?'}
    elif current_func is not None:
        if 'DW_AT_name' in line:
            m = re.search(r':\s*(.+?)$', line)
            if m: current_func['name'] = m.group(1).strip()
        elif 'DW_AT_low_pc' in line:
            m = re.search(r':\s*0x([0-9a-f]+)', line)
            if m: current_func['low_pc'] = int(m.group(1), 16)
        elif 'DW_AT_high_pc' in line:
            m = re.search(r':\s*(0x[0-9a-f]+|\d+)', line)
            if m:
                val = int(m.group(1), 0)
                # high_pc can be absolute or relative (offset from low_pc)
                if val < current_func['low_pc']:
                    current_func['high_pc'] = current_func['low_pc'] + val
                else:
                    current_func['high_pc'] = val
        elif 'DW_AT_decl_file' in line:
            m = re.search(r':\s*(\d+)', line)
            if m: current_func['file'] = m.group(1)
        elif 'DW_TAG_' in line and 'DW_TAG_subprogram' not in line:
            # Check if this function contains our target
            if current_func and current_func['low_pc'] > 0:
                for t in targets:
                    if current_func['low_pc'] <= t < current_func['high_pc']:
                        print(f'pc 0x{t:x} => {current_func[\"name\"]} (0x{current_func[\"low_pc\"]:x}-0x{current_func[\"high_pc\"]:x})')
            current_func = None
" 2>&1

